import { createClient } from '@/lib/supabase/server';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { ClipboardList, Plus, MessageSquare } from 'lucide-react';
import Link from 'next/link';
import { formatDistanceToNow } from 'date-fns';
import type { Survey } from '@/types';

const statusColors = {
  draft: 'secondary',
  active: 'default',
  closed: 'outline',
} as const;

export default async function SurveysPage() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return null;

  const { data: profile } = await supabase
    .from('profiles')
    .select('organization_id')
    .eq('id', user.id)
    .single();

  let surveys: Survey[] = [];
  if (profile?.organization_id) {
    const { data } = await supabase
      .from('surveys')
      .select('*')
      .eq('organization_id', profile.organization_id)
      .order('created_at', { ascending: false });
    surveys = (data as Survey[]) || [];
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Surveys</h1>
          <p className="text-muted-foreground">Create and manage feedback surveys</p>
        </div>
        <Button asChild>
          <Link href="/dashboard/surveys/create">
            <Plus className="mr-2 h-4 w-4" />
            Create Survey
          </Link>
        </Button>
      </div>

      {surveys.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-16 text-center">
          <div className="rounded-full bg-muted p-4 mb-4">
            <ClipboardList className="h-8 w-8 text-muted-foreground" />
          </div>
          <h3 className="text-lg font-semibold mb-1">No surveys yet</h3>
          <p className="text-sm text-muted-foreground max-w-sm mb-4">
            Create your first survey to start collecting customer feedback
          </p>
          <Button asChild>
            <Link href="/dashboard/surveys/create">
              <Plus className="mr-2 h-4 w-4" />
              Create Survey
            </Link>
          </Button>
        </div>
      ) : (
        <div className="space-y-3">
          {surveys.map((survey) => (
            <Link key={survey.id} href={`/dashboard/surveys/${survey.id}`}>
              <Card className="hover:shadow-md transition-shadow cursor-pointer">
                <CardContent className="p-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3 min-w-0">
                      <div className="rounded-lg bg-purple-50 dark:bg-purple-950 p-2.5 shrink-0">
                        <ClipboardList className="h-5 w-5 text-purple-600 dark:text-purple-400" />
                      </div>
                      <div className="min-w-0">
                        <p className="font-medium truncate">{survey.title}</p>
                        <p className="text-xs text-muted-foreground">
                          {survey.questions.length} question{survey.questions.length !== 1 ? 's' : ''} · 
                          Created {formatDistanceToNow(new Date(survey.created_at), { addSuffix: true })}
                        </p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3 shrink-0">
                      <div className="flex items-center gap-1 text-sm text-muted-foreground">
                        <MessageSquare className="h-4 w-4" />
                        {survey.response_count}
                      </div>
                      <Badge variant={statusColors[survey.status]}>
                        {survey.status.charAt(0).toUpperCase() + survey.status.slice(1)}
                      </Badge>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}
