            className="flex-1"
          >
            Yes
          </Button>
          <Button
            variant={value === 'No' ? 'default' : 'outline'}
            onClick={() => onChange('No')}
            className="flex-1"
          >
            No
          </Button>
        </div>
      )}
    </div>
  );
}
