import { Card, CardContent } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Plus, Trash2, GripVertical, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { nanoid } from 'nanoid';
import type { SurveyQuestion, SurveySettings } from '@/types';
import { QUESTION_TYPES } from '@/lib/constants';

interface SurveyBuilderProps {
  organizationId: string;
  initialData?: {
    title: string;
    description: string;
    questions: SurveyQuestion[];
    settings: SurveySettings;
  };
  surveyId?: string;
}

export function SurveyBuilder({ organizationId, initialData, surveyId }: SurveyBuilderProps) {
  const [title, setTitle] = useState(initialData?.title || '');
  const [description, setDescription] = useState(initialData?.description || '');
  const [questions, setQuestions] = useState<SurveyQuestion[]>(
    initialData?.questions || []
  );
  const [settings, setSettings] = useState<SurveySettings>(
    initialData?.settings || { anonymous: true, allowMultiple: false, closeDate: null }
  );
  const [saving, setSaving] = useState(false);
  const router = useRouter();

  const addQuestion = (type: SurveyQuestion['type'] = 'open_ended') => {
    const newQuestion: SurveyQuestion = {
      id: nanoid(),
      type,
      text: '',
      required: false,
      ...(type === 'multiple_choice' || type === 'single_choice'
        ? { options: ['Option 1', 'Option 2'] }
        : {}),
    };
    setQuestions([...questions, newQuestion]);
  };

  const updateQuestion = (index: number, updates: Partial<SurveyQuestion>) => {
    setQuestions(questions.map((q, i) => (i === index ? { ...q, ...updates } : q)));
  };

  const removeQuestion = (index: number) => {
    setQuestions(questions.filter((_, i) => i !== index));
  };

  const addOption = (questionIndex: number) => {
    const q = questions[questionIndex];
    if (q.options) {
      updateQuestion(questionIndex, {
        options: [...q.options, `Option ${q.options.length + 1}`],
      });
    }
  };

  const updateOption = (questionIndex: number, optionIndex: number, value: string) => {
    const q = questions[questionIndex];
    if (q.options) {
      const newOptions = [...q.options];
      newOptions[optionIndex] = value;
      updateQuestion(questionIndex, { options: newOptions });
    }
  };

  const removeOption = (questionIndex: number, optionIndex: number) => {
    const q = questions[questionIndex];
    if (q.options && q.options.length > 2) {
      updateQuestion(questionIndex, {
        options: q.options.filter((_, i) => i !== optionIndex),
      });
    }
  };

  const handleSave = async (status: 'draft' | 'active' = 'draft') => {
    if (!title.trim()) {
      toast.error('Survey title is required');
      return;
    }
    if (questions.length === 0) {
      toast.error('Add at least one question');
      return;
    }
    if (questions.some((q) => !q.text.trim())) {
      toast.error('All questions must have text');
      return;
    }

    setSaving(true);

    try {
      const url = surveyId ? `/api/surveys/${surveyId}` : '/api/surveys';
      const method = surveyId ? 'PATCH' : 'POST';

      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title,
          description,
          questions,
          settings,
          status,
          organization_id: organizationId,
        }),
      });

      if (!res.ok) throw new Error('Failed to save survey');

      const { data } = await res.json();
      toast.success(status === 'active' ? 'Survey published!' : 'Survey saved as draft');
      router.push(`/dashboard/surveys/${data?.id || surveyId}`);
      router.refresh();
    } catch {
      toast.error('Failed to save survey');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="space-y-6 max-w-3xl">
      <div className="space-y-4">
        <div className="space-y-2">
          <Label htmlFor="title">Survey Title</Label>
          <Input
            id="title"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="e.g., Customer Satisfaction Survey"
            className="text-lg"
          />
        </div>
        <div className="space-y-2">
          <Label htmlFor="description">Description (optional)</Label>
          <Textarea
            id="description"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="Tell respondents what this survey is about..."
            rows={2}
          />
        </div>
      </div>

      {/* Questions */}
      <div className="space-y-4">
        <Label className="text-base font-semibold">Questions</Label>

        {questions.length === 0 ? (
          <div className="text-center py-8 border rounded-lg border-dashed text-muted-foreground">
            <p className="text-sm">No questions added yet</p>
            <p className="text-xs mt-1">Click below to add your first question</p>
          </div>
        ) : (
          <div className="space-y-4">
            {questions.map((question, index) => (
              <Card key={question.id}>
                <CardContent className="p-4 space-y-3">
                  <div className="flex items-start gap-3">
                    <GripVertical className="h-5 w-5 text-muted-foreground mt-2 shrink-0 cursor-grab" />
                    <div className="flex-1 space-y-3">
                      <div className="flex gap-3">
                        <div className="flex-1">
                          <Input
                            value={question.text}
                            onChange={(e) => updateQuestion(index, { text: e.target.value })}
                            placeholder={`Question ${index + 1}`}
                          />
                        </div>
                        <Select
                          value={question.type}
                          onValueChange={(v) => updateQuestion(index, {
                            type: v as SurveyQuestion['type'],
                            ...(v === 'multiple_choice' || v === 'single_choice'
                              ? { options: question.options || ['Option 1', 'Option 2'] }
                              : { options: undefined }),
                          })}
                        >
                          <SelectTrigger className="w-44">
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            {QUESTION_TYPES.map((qt) => (
                              <SelectItem key={qt.value} value={qt.value}>
                                {qt.label}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                      </div>

                      {/* Options for MC/SC */}
                      {(question.type === 'multiple_choice' || question.type === 'single_choice') &&
                        question.options && (
                          <div className="space-y-2 pl-4">
                            {question.options.map((opt, optIdx) => (
                              <div key={optIdx} className="flex items-center gap-2">
                                <div className="w-4 h-4 rounded-full border border-muted-foreground/50 shrink-0" />
                                <Input
                                  value={opt}
                                  onChange={(e) => updateOption(index, optIdx, e.target.value)}
                                  className="h-8 text-sm"
                                />
                                {question.options!.length > 2 && (
                                  <Button
                                    variant="ghost"
                                    size="icon"
                                    className="h-8 w-8 shrink-0"
                                    onClick={() => removeOption(index, optIdx)}
                                  >
                                    <Trash2 className="h-3 w-3" />
                                  </Button>
                                )}
                              </div>
                            ))}
                            <Button
                              variant="ghost"
                              size="sm"
                              className="text-xs"
                              onClick={() => addOption(index)}
                            >
                              <Plus className="h-3 w-3 mr-1" />
                              Add option
                            </Button>
                          </div>
                        )}

                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-2">
                          <Switch
                            checked={question.required}
                            onCheckedChange={(checked) => updateQuestion(index, { required: checked })}
                          />
                          <span className="text-xs text-muted-foreground">Required</span>
                        </div>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => removeQuestion(index)}
                          className="text-destructive hover:text-destructive"
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}

        <div className="flex flex-wrap gap-2">
          {QUESTION_TYPES.map((qt) => (
            <Button
              key={qt.value}
              variant="outline"
              size="sm"
              onClick={() => addQuestion(qt.value as SurveyQuestion['type'])}
            >
              <Plus className="h-3 w-3 mr-1" />
              {qt.label}
            </Button>
          ))}
        </div>
      </div>

      {/* Settings */}
      <Card>
        <CardContent className="p-4 space-y-4">
          <Label className="text-base font-semibold">Settings</Label>
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium">Anonymous responses</p>
              <p className="text-xs text-muted-foreground">Allow responses without email</p>
            </div>
            <Switch
              checked={settings.anonymous}
              onCheckedChange={(checked) => setSettings({ ...settings, anonymous: checked })}
            />
          </div>
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium">Allow multiple responses</p>
              <p className="text-xs text-muted-foreground">Let users submit more than once</p>
            </div>
            <Switch
              checked={settings.allowMultiple}
              onCheckedChange={(checked) => setSettings({ ...settings, allowMultiple: checked })}
            />
          </div>
        </CardContent>
      </Card>

      {/* Actions */}
      <div className="flex gap-3 pt-4">
        <Button onClick={() => handleSave('draft')} variant="outline" disabled={saving}>
          {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
          Save as Draft
        </Button>
        <Button onClick={() => handleSave('active')} disabled={saving}>
          {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
          Publish Survey
        </Button>
      </div>
    </div>
  );
}

'use client';

import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Legend } from 'recharts';

const COLORS = ['#3b82f6', '#8b5cf6', '#ec4899', '#f59e0b', '#10b981', '#6366f1', '#f43f5e', '#14b8a6'];

interface ResponseChartProps {
  question: {
    id: string;
    text: string;
    type: string;
    options?: string[];
  };
  answers: (string | number | string[])[];
}

export function ResponseChart({ question, answers }: ResponseChartProps) {
  if (question.type === 'rating' || question.type === 'nps') {
    const counts: Record<string, number> = {};
    answers.forEach((a) => {
      const key = String(a);
      counts[key] = (counts[key] || 0) + 1;
    });

    const max = question.type === 'nps' ? 10 : 5;
    const data = Array.from({ length: max }, (_, i) => ({
      name: String(i + (question.type === 'nps' ? 0 : 1)),
      count: counts[String(i + (question.type === 'nps' ? 0 : 1))] || 0,
    }));

    const avg = answers.length > 0
      ? (answers.reduce((sum, a) => sum + Number(a), 0) / answers.length).toFixed(1)
      : '0';

    return (
      <Card>
        <CardHeader className="pb-2">
          <CardTitle className="text-sm font-medium">{question.text}</CardTitle>
          <p className="text-2xl font-bold">{avg} <span className="text-sm font-normal text-muted-foreground">avg</span></p>
        </CardHeader>
        <CardContent>
          <ResponsiveContainer width="100%" height={200}>
            <BarChart data={data}>
              <XAxis dataKey="name" fontSize={12} />
              <YAxis fontSize={12} allowDecimals={false} />
              <Tooltip />
              <Bar dataKey="count" fill="#3b82f6" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </CardContent>
      </Card>
    );
  }

  if (question.type === 'multiple_choice' || question.type === 'single_choice' || question.type === 'yes_no') {
    const counts: Record<string, number> = {};
    answers.forEach((a) => {
      if (Array.isArray(a)) {
        a.forEach((v) => { counts[v] = (counts[v] || 0) + 1; });
      } else {
        const key = String(a);
        counts[key] = (counts[key] || 0) + 1;
      }
    });

    const data = Object.entries(counts).map(([name, value]) => ({ name, value }));

    return (
      <Card>
        <CardHeader className="pb-2">
          <CardTitle className="text-sm font-medium">{question.text}</CardTitle>
          <p className="text-xs text-muted-foreground">{answers.length} responses</p>
        </CardHeader>
        <CardContent>
          <ResponsiveContainer width="100%" height={200}>
            <PieChart>
              <Pie data={data} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={80} label>
                {data.map((_, i) => (
                  <Cell key={i} fill={COLORS[i % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip />
              <Legend />
            </PieChart>
          </ResponsiveContainer>
        </CardContent>
      </Card>
    );
  }

  // Open-ended: just show count
  return (
    <Card>
      <CardHeader className="pb-2">
        <CardTitle className="text-sm font-medium">{question.text}</CardTitle>
      </CardHeader>
      <CardContent>
        <p className="text-2xl font-bold">{answers.length}</p>
        <p className="text-xs text-muted-foreground">text responses</p>
      </CardContent>
    </Card>
  );
}

'use client';

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { PieChart, Pie, Cell, ResponsiveContainer, Legend, Tooltip } from 'recharts';
import type { AnalysisResults } from '@/types';

const SENTIMENT_COLORS = {
  positive: '#10b981',
  neutral: '#6b7280',
  negative: '#ef4444',
};

interface AnalysisReportProps {
  results: AnalysisResults;
}

export function AnalysisReport({ results }: AnalysisReportProps) {
  const sentimentData = [
    { name: 'Positive', value: Math.round(results.sentiment.positive * 100) },
    { name: 'Neutral', value: Math.round(results.sentiment.neutral * 100) },
    { name: 'Negative', value: Math.round(results.sentiment.negative * 100) },
  ];

  return (
    <div className="space-y-6">
      {/* Summary */}
      <Card>
        <CardHeader>
          <CardTitle>Executive Summary</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-muted-foreground leading-relaxed">{results.summary}</p>
        </CardContent>
      </Card>

      <div className="grid gap-6 md:grid-cols-2">
        {/* Sentiment */}
        <Card>
          <CardHeader>
            <CardTitle>Sentiment Distribution</CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={250}>
              <PieChart>
                <Pie
                  data={sentimentData}
                  dataKey="value"
                  nameKey="name"
                  cx="50%"
                  cy="50%"
                  outerRadius={80}
                  label={({ name, value }) => `${name}: ${value}%`}
                >
                  <Cell fill={SENTIMENT_COLORS.positive} />
                  <Cell fill={SENTIMENT_COLORS.neutral} />
                  <Cell fill={SENTIMENT_COLORS.negative} />
                </Pie>
                <Tooltip />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>

        {/* NPS */}
        {results.nps_score !== undefined && (
          <Card>
            <CardHeader>
              <CardTitle>NPS Score</CardTitle>
              <CardDescription>Net Promoter Score</CardDescription>
            </CardHeader>
            <CardContent className="flex items-center justify-center">
              <div className="text-center">
                <div className={`text-6xl font-bold ${
                  results.nps_score >= 50 ? 'text-green-600' :
                  results.nps_score >= 0 ? 'text-yellow-600' : 'text-red-600'
                }`}>
                  {results.nps_score}
                </div>
                <p className="text-sm text-muted-foreground mt-2">
                  {results.nps_score >= 50 ? 'Excellent' :
                   results.nps_score >= 0 ? 'Good' : 'Needs Improvement'}
                </p>
              </div>
            </CardContent>
          </Card>
        )}
      </div>

      {/* Themes */}
      {results.themes.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle>Key Themes</CardTitle>
            <CardDescription>Automatically detected topics from responses</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {results.themes.map((theme, index) => (
                <div key={index} className="border rounded-lg p-4">
                  <div className="flex items-center justify-between mb-2">
                    <h4 className="font-semibold">{theme.name}</h4>
                    <div className="flex items-center gap-2">
                      <Badge variant="secondary">{theme.count} mentions</Badge>
                      <Badge
                        variant={theme.sentiment > 0.3 ? 'default' : theme.sentiment < -0.3 ? 'destructive' : 'secondary'}
                      >
                        {theme.sentiment > 0.3 ? 'Positive' : theme.sentiment < -0.3 ? 'Negative' : 'Neutral'}
                      </Badge>
                    </div>
                  </div>
                  {theme.examples.length > 0 && (
                    <div className="space-y-1">
                      {theme.examples.slice(0, 2).map((example, i) => (
                        <p key={i} className="text-sm text-muted-foreground italic">
                          &ldquo;{example}&rdquo;
                        </p>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Recommendations */}
      {results.recommendations.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle>AI Recommendations</CardTitle>
            <CardDescription>Action items based on feedback analysis</CardDescription>
          </CardHeader>
          <CardContent>
            <ol className="space-y-3">
              {results.recommendations.map((rec, index) => (
                <li key={index} className="flex gap-3">
                  <span className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-primary text-xs text-primary-foreground font-medium">
                    {index + 1}
                  </span>
                  <p className="text-sm text-muted-foreground">{rec}</p>
                </li>
              ))}
            </ol>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { createClient } from '@/lib/supabase/server';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { ClipboardList, Plus, MessageSquare } from 'lucide-react';
import Link from 'next/link';
import { formatDistanceToNow } from 'date-fns';
import type { Survey } from '@/types';

const statusColors = {
  draft: 'secondary',
  active: 'default',
  closed: 'outline',
} as const;

export default async function SurveysPage() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return null;

  const { data: profile } = await supabase
    .from('profiles')
    .select('organization_id')
    .eq('id', user.id)
    .single();

  let surveys: Survey[] = [];
  if (profile?.organization_id) {
    const { data } = await supabase
      .from('surveys')
      .select('*')
      .eq('organization_id', profile.organization_id)
      .order('created_at', { ascending: false });
    surveys = (data as Survey[]) || [];
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Surveys</h1>
          <p className="text-muted-foreground">Create and manage feedback surveys</p>
        </div>
        <Button asChild>
          <Link href="/dashboard/surveys/create">
            <Plus className="mr-2 h-4 w-4" />
            Create Survey
          </Link>
        </Button>
      </div>

      {surveys.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-16 text-center">
          <div className="rounded-full bg-muted p-4 mb-4">
            <ClipboardList className="h-8 w-8 text-muted-foreground" />
          </div>
          <h3 className="text-lg font-semibold mb-1">No surveys yet</h3>
          <p className="text-sm text-muted-foreground max-w-sm mb-4">
            Create your first survey to start collecting customer feedback
          </p>
          <Button asChild>
            <Link href="/dashboard/surveys/create">
              <Plus className="mr-2 h-4 w-4" />
              Create Survey
            </Link>
          </Button>
        </div>
      ) : (
        <div className="space-y-3">
          {surveys.map((survey) => (
            <Link key={survey.id} href={`/dashboard/surveys/${survey.id}`}>
              <Card className="hover:shadow-md transition-shadow cursor-pointer">
                <CardContent className="p-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3 min-w-0">
                      <div className="rounded-lg bg-purple-50 dark:bg-purple-950 p-2.5 shrink-0">
                        <ClipboardList className="h-5 w-5 text-purple-600 dark:text-purple-400" />
                      </div>
                      <div className="min-w-0">
                        <p className="font-medium truncate">{survey.title}</p>
                        <p className="text-xs text-muted-foreground">
                          {survey.questions.length} question{survey.questions.length !== 1 ? 's' : ''} · 
                          Created {formatDistanceToNow(new Date(survey.created_at), { addSuffix: true })}
                        </p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3 shrink-0">
                      <div className="flex items-center gap-1 text-sm text-muted-foreground">
                        <MessageSquare className="h-4 w-4" />
                        {survey.response_count}
                      </div>
                      <Badge variant={statusColors[survey.status]}>
                        {survey.status.charAt(0).toUpperCase() + survey.status.slice(1)}
                      </Badge>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}

import { createClient } from '@/lib/supabase/server';
import { redirect } from 'next/navigation';
import { SurveyBuilder } from '@/components/surveys/survey-builder';

export default async function CreateSurveyPage() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) redirect('/login');

  const { data: profile } = await supabase
    .from('profiles')
    .select('organization_id')
    .eq('id', user.id)
    .single();

  if (!profile?.organization_id) {
    return (
      <div className="text-center py-16">
        <p className="text-muted-foreground">Please set up your organization first.</p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Create Survey</h1>
        <p className="text-muted-foreground">
          Build a survey to collect customer feedback
        </p>
      </div>
      <SurveyBuilder organizationId={profile.organization_id} />
    </div>
  );
}

import { createClient } from '@/lib/supabase/server';
import { notFound } from 'next/navigation';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { ResponseChart } from '@/components/surveys/response-chart';
import { ClipboardList, ExternalLink, MessageSquare, Copy } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import Link from 'next/link';
import type { Survey, SurveyResponse } from '@/types';

export default async function SurveyDetailPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const supabase = await createClient();

  const { data: survey } = await supabase
    .from('surveys')
    .select('*')
    .eq('id', id)
    .single();

  if (!survey) notFound();

  const typedSurvey = survey as Survey;

  const { data: responses } = await supabase
    .from('survey_responses')
    .select('*')
    .eq('survey_id', id)
    .order('created_at', { ascending: false });

  const typedResponses = (responses || []) as SurveyResponse[];
  const publicUrl = `${process.env.NEXT_PUBLIC_APP_URL || ''}/s/${id}`;

  return (
    <div className="space-y-6">
      <div className="flex items-start justify-between">
        <div className="flex items-start gap-4">
          <div className="rounded-lg bg-purple-50 dark:bg-purple-950 p-3">
            <ClipboardList className="h-6 w-6 text-purple-600 dark:text-purple-400" />
          </div>
          <div>
            <h1 className="text-2xl font-bold tracking-tight">{typedSurvey.title}</h1>
            <p className="text-sm text-muted-foreground">
              {typedSurvey.questions.length} questions · {typedSurvey.response_count} responses
            </p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <Badge variant={typedSurvey.status === 'active' ? 'default' : 'secondary'}>
            {typedSurvey.status}
          </Badge>
          {typedSurvey.status === 'active' && (
            <Button variant="outline" size="sm" asChild>
              <Link href={publicUrl} target="_blank">
                <ExternalLink className="h-4 w-4 mr-1" />
                Preview
              </Link>
            </Button>
          )}
        </div>
      </div>

      {/* Share URL */}
      {typedSurvey.status === 'active' && (
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-3">
              <div className="flex-1 bg-muted rounded-md px-3 py-2 text-sm font-mono truncate">
                {publicUrl}
              </div>
              <Button variant="outline" size="sm">
                <Copy className="h-4 w-4 mr-1" />
                Copy
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      <Tabs defaultValue="responses">
        <TabsList>
          <TabsTrigger value="responses">
            <MessageSquare className="h-4 w-4 mr-1" />
            Responses ({typedResponses.length})
          </TabsTrigger>
          <TabsTrigger value="charts">Charts</TabsTrigger>
          <TabsTrigger value="analysis">AI Analysis</TabsTrigger>
        </TabsList>

        <TabsContent value="responses" className="space-y-4 mt-4">
          {typedResponses.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground">
              <MessageSquare className="mx-auto h-8 w-8 mb-2 opacity-50" />
              <p className="text-sm">No responses yet</p>
              <p className="text-xs mt-1">Share the survey link to start collecting responses</p>
            </div>
          ) : (
            typedResponses.map((response) => (
              <Card key={response.id}>
                <CardContent className="p-4">
                  <div className="flex items-center justify-between mb-3">
                    <p className="text-xs text-muted-foreground">
                      {formatDistanceToNow(new Date(response.created_at), { addSuffix: true })}
                    </p>
                    {response.respondent_email && (
                      <p className="text-xs text-muted-foreground">{response.respondent_email}</p>
                    )}
                  </div>
                  <div className="space-y-2">
                    {typedSurvey.questions.map((q) => (
                      <div key={q.id} className="text-sm">
                        <p className="font-medium">{q.text}</p>
                        <p className="text-muted-foreground">
                          {response.answers[q.id] !== undefined
                            ? Array.isArray(response.answers[q.id])
                              ? (response.answers[q.id] as string[]).join(', ')
                              : String(response.answers[q.id])
                            : 'No answer'}
                        </p>
                      </div>
                    ))}
                  </div>
                </CardContent>
              </Card>
            ))
          )}
        </TabsContent>

        <TabsContent value="charts" className="mt-4">
          {typedResponses.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground">
              <p className="text-sm">Collect responses to see charts</p>
            </div>
          ) : (
            <div className="grid gap-4 md:grid-cols-2">
              {typedSurvey.questions.map((q) => (
                <ResponseChart
                  key={q.id}
                  question={q}
                  answers={typedResponses
                    .map((r) => r.answers[q.id])
                    .filter((a) => a !== undefined && a !== null)}
                />
              ))}
            </div>
          )}
        </TabsContent>

        <TabsContent value="analysis" className="mt-4">
          <AnalysisTab surveyId={id} />
        </TabsContent>
      </Tabs>
    </div>
  );
}

// Client component for analysis tab
async function AnalysisTab({ surveyId }: { surveyId: string }) {
  const supabase = await createClient();

  const { data: analysis } = await supabase
    .from('analyses')
    .select('*')
    .eq('survey_id', surveyId)
    .order('created_at', { ascending: false })
    .limit(1)
    .single();

  if (!analysis) {
    return (
      <div className="text-center py-12">
        <p className="text-muted-foreground mb-4">No analysis yet</p>
        <AnalyzeButton surveyId={surveyId} />
      </div>
    );
  }

  // Import and use AnalysisReport dynamically to use the component
  const { AnalysisReport } = await import('@/components/surveys/analysis-report');
  return (
    <div className="space-y-4">
      <div className="flex justify-end">
        <AnalyzeButton surveyId={surveyId} label="Re-analyze" />
      </div>
      <AnalysisReport results={analysis.results} />
    </div>
  );
}

// Simple client button for triggering analysis
function AnalyzeButton({ surveyId, label = 'Run AI Analysis' }: { surveyId: string; label?: string }) {
  return (
    <form action={`/api/surveys/${surveyId}/analyze`} method="POST">
      <Button type="submit">{label}</Button>
    </form>
  );
}

import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/lib/supabase/server';

export async function GET() {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const { data: profile } = await supabase
      .from('profiles')
      .select('organization_id')
      .eq('id', user.id)
      .single();

    if (!profile?.organization_id) {
      return NextResponse.json({ data: [] });
    }

    const { data, error } = await supabase
      .from('surveys')
      .select('*')
      .eq('organization_id', profile.organization_id)
      .order('created_at', { ascending: false });

    if (error) return NextResponse.json({ error: error.message }, { status: 500 });
    return NextResponse.json({ data });
  } catch {
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await request.json();
    const { title, description, questions, settings, status, organization_id } = body;

    if (!title || !organization_id) {
      return NextResponse.json({ error: 'Title and organization are required' }, { status: 400 });
    }

    const { data, error } = await supabase
      .from('surveys')
      .insert({
        organization_id,
        created_by: user.id,
        title,
        description: description || null,
        questions: questions || [],
        settings: settings || { anonymous: true, allowMultiple: false, closeDate: null },
        status: status || 'draft',
      })
      .select()
      .single();

    if (error) return NextResponse.json({ error: error.message }, { status: 500 });
    return NextResponse.json({ data }, { status: 201 });
  } catch {
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/lib/supabase/server';

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id: surveyId } = await params;
    const supabase = await createClient();

    // Check if survey is active (no auth required for public responses)
    const { data: survey, error: surveyError } = await supabase
      .from('surveys')
      .select('id, status, settings')
      .eq('id', surveyId)
      .single();

    if (surveyError || !survey) {
      return NextResponse.json({ error: 'Survey not found' }, { status: 404 });
    }

    if (survey.status !== 'active') {
      return NextResponse.json({ error: 'Survey is not accepting responses' }, { status: 400 });
    }

    const body = await request.json();
    const { answers, respondent_email } = body;

    if (!answers || typeof answers !== 'object') {
      return NextResponse.json({ error: 'Answers are required' }, { status: 400 });
    }

    const { data, error } = await supabase
      .from('survey_responses')
      .insert({
        survey_id: surveyId,
        answers,
        respondent_email: respondent_email || null,
        metadata: {
          user_agent: request.headers.get('user-agent'),
          timestamp: new Date().toISOString(),
        },
      })
      .select()
      .single();

    if (error) return NextResponse.json({ error: error.message }, { status: 500 });
    return NextResponse.json({ data }, { status: 201 });
  } catch {
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

